def build_report(tasks):
    done_count = 0
    lines = ["Task Summary", "------------"]

    for task in tasks:
        if task.done:
            done_count += 1
        lines.append(f"- {task.label()}")

    lines.append(f"Completed: {done_count}")
    lines.append(f"Remaining: {len(tasks) - done_count}")
    return "\n".join(lines)

